function ModelHalidom:OnModelInit()
	self:ModelNetMsgRecv(LProtoIds.HalidomInfoResp,function(...) self:OnHalidomInfoResp(...) end)
	self:ModelNetMsgRecv(LProtoIds.HalidomStarUpResp,function(...) self:OnHalidomStarUpResp(...) end)
	self:ModelNetMsgRecv(LProtoIds.HalidomCollectUpgradeResp,function(...) self:OnHalidomCollectUpgradeResp(...) end)
	self:ModelNetMsgRecv(LProtoIds.HalidomDrawResp,function(...) self:OnHalidomDrawResp(...) end)
	self:ModelNetMsgRecv(LProtoIds.HalidomProgressRewardResp,function(...) self:OnHalidomProgressRewardResp(...) end)
	self:ModelNetMsgRecv(LProtoIds.HalidomAddExpResp,function(...) self:OnHalidomAddExpResp(...) end)
	self:ModelEventRecv(EventNames.REFRESH_FUNCTION_STATE,function() self:CheckIsReqInfo() end)

	--- 是否已经查看圣物召唤界面
	self._isEnterHalidomCall = false

	self:InitHalidomRef()
	self:InitHalidomLuckyRefDatas()
	self:InitHalidomStarRef()
	self:InitHalidomCollectRefDatas()
end

