function ModelHalidom:GetHalidomRewardLvWeightList(jackpotLv)
	jackpotLv = jackpotLv or self:GetHalidomJackpotLv()
	if not self._initHalidomRewardLvWeightList then
		self._initHalidomRewardLvWeightList = {}
	end
	local info = self._initHalidomRewardLvWeightList[jackpotLv]
	if not info then
		local ref = GameTable.HalidomRewardLvRef[jackpotLv]
		if ref then
			info = {}
			local weight = string.split(ref.weight,",")
			for i,v in ipairs(weight) do
				v = string.split(v,"=")
				table.insert(info,{
					jackpotId = tonumber(v[1]),
					weightNum = tonumber(v[2])
				})
			end
			self._initHalidomRewardLvWeightList[jackpotLv] = info
		end
	end
	return info
end


function ModelHalidom:GetHalidomRewardLvIdleShowList(jackpotLv)
	jackpotLv = jackpotLv or self:GetHalidomJackpotLv()
	local results = {}
	local infos = self:GetHalidomRewardLvWeightList(jackpotLv)
	for i,v in ipairs(infos) do
		local list = self:GetNoSameIdleShowList(v.jackpotId)
		for idx,ref in ipairs(list) do
			table.insert(results,ref)
		end
	end
	return results
end

function ModelHalidom:GetNoSameIdleShowList(jackpotId)
	local list = self:GetHalidomRewardRefByType(jackpotId)
	if list and #list > 0 then
		local recordKeyMap = {}
		for i,v in ipairs(list) do
			if v.idleShow and v.idleShow > 0 then
				local recordKeys = recordKeyMap[v.idleShow]
				if not recordKeys then
					recordKeys = {}
					recordKeyMap[v.idleShow] = recordKeys
				end
				table.insert(recordKeys,v)
			end
		end
		local results = {}
		for idleShow,records in pairs(recordKeyMap) do
--[[			local randomNum = math.random(1,#records)
			table.insert(results,records[randomNum])]]
			for i,v in ipairs(records) do
				table.insert(results,v)
			end
		end
		return results
	end
	return {}
end


function ModelHalidom:GetHalidomRewardLvShowList(jackpotLv)
	jackpotLv = jackpotLv or self:GetHalidomJackpotLv()
	local results = {}
	local infos = self:GetHalidomRewardLvWeightList(jackpotLv)
	for i,v in ipairs(infos) do
		local list = self:GetNoSameShowList(v.jackpotId)
		for idx,ref in ipairs(list) do
			table.insert(results,ref)
		end
	end
	return results
end

function ModelHalidom:GetNoSameShowList(jackpotId)
	local list = self:GetHalidomRewardRefByType(jackpotId)
	if list and #list > 0 then
		local recordKeyMap = {}
		for i,v in ipairs(list) do
			local recordKeys = recordKeyMap[v.show]
			if not recordKeys then
				recordKeys = {}
				recordKeyMap[v.show] = recordKeys
			end
			table.insert(recordKeys,v)
		end
		local results = {}
		for idleShow,records in pairs(recordKeyMap) do
			local randomNum = math.random(1,#records)
			table.insert(results,records[randomNum])
		end
		table.sort(results,function(a,b)
			return a.idleShow < b.idleShow
		end)
		return results
	end
	return {}
end
