function ModelHalidom:InitHalidomRef()
	local initHalidomRefMap = {}
	local initHalidomRefTypeMap = {}
	for k,v in pairs(GameTable.HalidomRef) do
		local type = v.type
		local initHalidomRefTypeDatas = initHalidomRefTypeMap[type]
		if not initHalidomRefTypeDatas then
			initHalidomRefTypeDatas = {}
			initHalidomRefTypeMap[type] = initHalidomRefTypeDatas
		end
		local data = {
			refId = k,
			type = type,
			name = ccLngText(v.name),
			sort = v.sort,
			icon = v.icon,
			star = v.star,
			condition = v.condition,
			num = v.num,
			numItem = LxDataHelper.ParseItem_3(v.num),
			desc = ccLngText(v.desc),
		}
		table.insert(initHalidomRefTypeDatas,data)
		initHalidomRefMap[k] = data
	end
	self._initHalidomRefMap = initHalidomRefMap
	self._initHalidomRefTypeMap = initHalidomRefTypeMap
end

