function ModelHalidom:InitHalidomStarRef()
	local recordLvRefIdMap = {}
	local starMap = {}
	for k,v in pairs(GameTable.HalidomStarRef) do
		local halidomId = v.halidomId
		local refIdMap = starMap[halidomId]
		if not refIdMap then
			refIdMap = {}
			starMap[halidomId] = refIdMap
		end
		table.insert(refIdMap,v)

		local recordLvRefIdDatas = recordLvRefIdMap[halidomId]
		if not recordLvRefIdDatas then
			recordLvRefIdDatas = {}
			recordLvRefIdMap[halidomId] = recordLvRefIdDatas
		end
		recordLvRefIdDatas[v.lv] = k
	end
	for k,v in pairs(starMap) do
		table.sort(v,function(a, b) return a.lv < b.lv end)
	end
	---@type table<number,table<V_HalidomStarRef>>
	self._initHalidomStarRefMap = starMap

	---@type table<number,table<number>>
	self._recordLvRefIdMap = recordLvRefIdMap
end

