function ModelHalidom:GetHalidomStarAttrListByRefId(refId)
	if not self._initHalidomStarAttrList then
		self._initHalidomStarAttrList = {}
	end
	local initHalidomStarAttrList = self._initHalidomStarAttrList
	local attrList = initHalidomStarAttrList[refId]
	if not attrList then
		attrList = {}

		local ref = self:GetHalidomStarRefByRefId(refId)
