--- 下一级所需要的碎片数量 解析
function ModelHalidom:GetSplitHalidomStarNextNumByRefId(refId)
	if self:CheckHalidomStarIsMax(refId) then return end
	if not self._initHalidomStarNextNumItemMap then
		self._initHalidomStarNextNumItemMap = {}
	end
	local data = self._initHalidomStarNextNumItemMap[refId]
	if not data then
		local nextNum = self:GetHalidomStarNextNumByRefId(refId)
		data = LxDataHelper.ParseItem_4(nextNum)
		self._initHalidomStarNextNumItemMap[refId] = data
	end
	return data
end

--- -1 代表满星
function ModelHalidom:CheckHalidomStarIsMax(refId)
	local nextNum = self:GetHalidomStarNextNumByRefId(refId)
	return nextNum == "-1"
end

