function ModelHalidom:InitHalidomLuckyRefDatas()
	local refMap = {}
	local recordGradRewardMap = {}
	for k,v in pairs(GameTable.HalidomLuckyRef) do
		local typeRefs = refMap[v.type]
		if not typeRefs then
			typeRefs = {}
			refMap[v.type] = typeRefs
		end
		local data = self:_GetHalidomLuckyRef(v)
		table.insert(typeRefs,data)
		recordGradRewardMap[k] = {
			reward = data.gradReward
		}
	end

	local list = {}
	for k,v in pairs(refMap) do
		table.sort(v,function(a, b) return a.grad < b.grad end)
		table.insert(list,{
			type = k,
			list = v,
		})
	end
	table.sort(list,function(a, b) return a.type < b.type end)
	self._initHalidomLuckyRefList = list
	self._initHalidomLuckyGradRewardMap = recordGradRewardMap
end

function ModelHalidom:GetHalidomLuckyRefDatas()
	return self._initHalidomLuckyRefList
end

function ModelHalidom:GetHalidomLuckyRef(refId)
	return GameTable.HalidomLuckyRef[refId]
end

function ModelHalidom:_GetHalidomLuckyRef(ref)
	return {
		refId = ref.refId,
		type = ref.type,
		grad = ref.grad,
		gradReward = LxDataHelper.ParseItem_3(ref.gradReward)
	}
end

