function ModelHalidom:OnHalidomInfoResp(pb)
	self._info = self:CreateStructHalidomInfo(pb)
end

function ModelHalidom:OnHalidomStarUpResp(pb)
	local info = self:GetHalidomInfo()
	if not info then return end

	local obj = pb.obj
	local objRefId = obj.refId
	local isActHalidom = info:CheckIsActHalidomObj(objRefId)

	---@type StructHalidomObjInfo
	local oldHalidom = nil
	if not isActHalidom then
		---@type StructHalidomObjInfo
		local oldHalidomObj = info:GetHalidomObjByRefId(objRefId)

		oldHalidom = info:CreateStructHalidomObjInfo(oldHalidomObj)

	end
	---@type StructHalidomObjInfo
	local newHalidom = info:UpdateObjByRefId(obj)

	GF.OpenWnd("UISdOpt",{
		optType = isActHalidom and 1 or 2,
		oldHalidom = oldHalidom,
		newHalidom = newHalidom,
	})
	info:UpdateCollectObjByRefId(pb.collectInfo)

end

function ModelHalidom:OnHalidomCollectUpgradeResp(pb)
	if not self._info then return end
	self._info:UpdateCollectObjByRefId(pb.collectInfo)
end

function ModelHalidom:OnHalidomDrawResp(pb)
	if not self._info then return end
	self._info:SetCommonData(pb)

--[[	if self:CheckIsHalidomDrawJumpAni() then
		--- 跳过动画
	else
		--- 播放召唤特效
	end
	self:DisposeRewardIds(pb,ModelHalidom.WAY_REWARD_DRAW)]]
end

function ModelHalidom:OnHalidomProgressRewardResp(pb)
	if not self._info then return end
	self._info:SetProgressRewardId(pb.progressRewardId)
	self._info:SetProgressRewardLv(pb.progressRewardLv)

	self:DisposeRewardIds(pb,ModelHalidom.WAY_REWARD_PROGRESS)
end

function ModelHalidom:OnHalidomAddExpResp(pb)
	local info = self:GetHalidomInfo()
	if not info then return end

	info:UpdateObjByRefId(pb.obj)
	info:UpdateCollectObjByRefId(pb.collectInfo)
end

