function ModelHalidom:GetHalidomLuckNum()
	local data = self._initHalidomLuckNumMap
	if not data then
		data = {}
		--- 按奖池等级给每次抽取获得的积分数量。奖池等级|积分道具
		local halidomLuckNum = self:GetHalidomConfigRefByKey("halidomLuckNum")
		local halidomLuckNums = string.split(halidomLuckNum,",")
		for i,v in ipairs(halidomLuckNums) do
			v = string.split(v,"|")
			data[tonumber(v[1])] = {
				item = LxDataHelper.ParseItem_3(v[2])
			}
		end
		self._initHalidomLuckNumMap = data
	end
	return data
end

---@return table itemType,itemId,itemNum
function ModelHalidom:GetHalidomReward()
	local progressRewardLv = self:GetHalidomProgressRewardLv()
	--local jackpotLv = self:GetHalidomJackpotLv()
	local initHalidomLuckNumMap = self:GetHalidomLuckNum()
	local data = initHalidomLuckNumMap[progressRewardLv]
	if not data then
		data = initHalidomLuckNumMap[1]
	end
	return data.item
end

