function ModelHalidom:GetHalidomLuckyRewardsByJackpotLv(jackpotLv)
	if not self._halidomLuckyRewards then
		self._halidomLuckyRewards = {}
	end
	local halidomLuckyRewards = self._halidomLuckyRewards
	local data = halidomLuckyRewards[jackpotLv]
	if not data then
		local list = {}
		local initHalidomLuckyRefList = self:GetHalidomLuckyRefDatas()
		for i,v in ipairs(initHalidomLuckyRefList) do
			if v.type == jackpotLv then
				list = v.list
				break
			end
		end

		data = {}
		local beforeGrad = 0
		for i,v in ipairs(list) do
			table.insert(data,{
				refId = v.refId,
				type = v.type,
				grad = v.grad,
				gradReward = v.gradReward,
				beforeGrad = beforeGrad,
			})
			beforeGrad = v.grad
		end
		halidomLuckyRewards[jackpotLv] = data
	end
	return data
end

function ModelHalidom:GetCurJackpotItemNum()
	local item = self:GetHalidomReward()
	if not item then return 0 end
	local itemId = item.itemId
	return gModelItem:GetNumByRefId(itemId)
end

function ModelHalidom:GetNextHalidomRewardLvNum()
	local nextJackpotLv = self:GetHalidomJackpotLv() + 1
	return self:GetHalidomRewardLvNum(nextJackpotLv)
end

function ModelHalidom:CheckIsMaxJackpotLv()
	local nextNum = self:GetNextHalidomRewardLvNum()
	return nextNum == nil
end

function ModelHalidom:GetHalidomRewardImageNums()
	if self:CheckIsMaxJackpotLv() then return end

	local nextNum = self:GetNextHalidomRewardLvNum()
	local drawCnt = self:GetHalidomDrawCnt()
	local lostNum = nextNum - drawCnt
	if lostNum < 1 then return end

	local numStr = {}
	lostNum = tostring(lostNum)
	local num
	for i = 1,string.len(lostNum) do
		num = string.sub(lostNum,i,i)
		table.insert(numStr,tonumber(num))
	end
	return numStr
end

function ModelHalidom:_GetInitHalidomRewardRefData(v)
	return {
		refId = v.refId,
		type = v.type,
		--- 仅支持单一奖励配置
		reward = LxDataHelper.ParseItem_4(v.reward),
		extractMax = v.extractMax,
		idleShow = v.idleShow,
		show = v.show,
		showBig = v.showBig,
	}
end

--- 根据类型获取奖池表数据
function ModelHalidom:GetHalidomRewardRefByType(itype)
	if not self._initHalidomRewardRef then
		self._initHalidomRewardRef = {}
	end
	local list = self._initHalidomRewardRef[itype]
	if not list then
		list = {}
		for k,v in pairs(GameTable.HalidomRewardRef) do
			if v.type == itype then
				table.insert(list,self:_GetInitHalidomRewardRefData(v))
			end
		end
		table.sort(list,function(a, b) return a.refId < b.refId end)
		self._initHalidomRewardRef[itype] = list
	end
	return list
end

--- 根据类型获取奖池表数据
function ModelHalidom:GetHalidomRewardByRefId(refId)
	if not self._initHalidomRewardList then
		self._initHalidomRewardList = {}
	end
	local data = self._initHalidomRewardList[refId]
	if not data then
		local ref = GameTable.HalidomRewardRef[refId]
		if ref then
			data = self:_GetInitHalidomRewardRefData(ref)
			self._initHalidomRewardList[refId] = data
		end
	end
	return data
end

function ModelHalidom:CheckHalidomRewardIsShowBig(refId)
	local ref = self:GetHalidomRewardByRefId(refId)
	if not ref then return false end
	return ref.showBig and ref.showBig == 1
end

--- 4.4概率公示弹窗
--- 根据奖池等级表的 weight 字段获取奖池id，再根据奖池id展示
function ModelHalidom:GetHalidomExplainShowList()
	local list = self._halidomExplainShowList
	if not list then
		local map = {}
		local htype
		for k,v in pairs(GameTable.HalidomExplainRef) do
			htype = v.type
			local mapDatas = map[htype]
			if not mapDatas then
				mapDatas = {}
				map[htype] = mapDatas
			end
			table.insert(mapDatas,{
				refId = k,
				type = htype,
				num = v.num,
				numStr = string.replace(ccClientText(41534),v.num / 100),
				reward = LxDataHelper.ParseItem_4(v.reward),
			})
		end

		list = {}
		for k,v in pairs(map) do
			table.sort(v,function(a, b) return a.refId < b.refId end)
			table.insert(list,{
				type = k,
				refData = v,
			})
		end
		table.sort(list,function(a, b) return a.type < b.type end)
		self._halidomExplainShowList = list
	end
	return list
end


--- 4.3积分奖励预览弹窗
function ModelHalidom:GetHalidomLuckyRewards()
	local list = self._halidomRewardLvList
	if not list then
		list = {}
		local initHalidomLuckyRefList = self:GetHalidomLuckyRefDatas()
		for i,v in ipairs(initHalidomLuckyRefList) do
			table.insert(list,{
				lv = v.type,
				refData = v.list
			})
		end
		self._halidomRewardLvList = list
	end
	return list
end


function ModelHalidom:GetHalidomTypeRefList()
	local list = {}
	local isLock
	for k,v in pairs(GameTable.HalidomTypeRef) do
		local typeList = {}
		local unlockTypeNum = 0
		local initHalidomRefTypeDatas = self._initHalidomRefTypeMap[k]
		if initHalidomRefTypeDatas and #initHalidomRefTypeDatas > 0 then
			for idx,val in ipairs(initHalidomRefTypeDatas) do
				local map = {}
				for key,data in pairs(val) do
					map[key] = data
				end
				map.halidomObj = self:GetHalidomObjByRefId(val.refId)
				if map.halidomObj then
					unlockTypeNum = unlockTypeNum + 1
				end
				table.insert(typeList,map)
			end
		end
		table.sort(typeList,function(a,b) return a.sort < b.sort end)
		isLock = self:CheckIsLockHalidomType(k)
		if isLock and unlockTypeNum > 0 then
			--- 判断是否已经有圣物解锁了
			isLock = false
		end
		table.insert(list,{
			refId = k,
			--- 类型名称
			name = ccLngText(v.name),
			sort = v.sort,
			--- 加入奖池等级
			condition = v.condition,
			--- 未开启描述
			desc = ccLngText(v.desc),
			collectObj = self:GetHalidomCollectObjByRefId(k),
			isLock = isLock,
			typeList = typeList,
		})
	end
	table.sort(list,function(a,b) return a.sort < b.sort end)
	return list
end



