function ModelHalidom:GetRewardListByPb(pb,way)
	--- 抽到的奖励id，奖池表id
	local rewardIds = pb.rewardIds
	if #rewardIds < 1 then return {} end

	local list = {}
	for i,v in ipairs(rewardIds) do
		local data = nil
		if way == ModelHalidom.WAY_REWARD_DRAW then
			data = self:GetHalidomRewardByRefId(v)
		elseif way == ModelHalidom.WAY_REWARD_PROGRESS then
			data = self._initHalidomLuckyGradRewardMap[v]
		end
		if data then
			table.insert(list,{
				reward = data.reward,
			})
		end
	end
	return list
end

function ModelHalidom:CheckHasRewardUI()
	local wndIns = GF.FindFirstWndByName("UISdAward")
	return wndIns ~= nil
end

--- 处理抽取到的奖励
function ModelHalidom:DisposeRewardIds(pb,way)
	if self:CheckHasRewardUI() then return end

	local rewardList = self:GetRewardListByPb(pb,way)
	if #rewardList < 1 then return end

	GF.OpenWndTop("UISdAward",{
		rewardList = rewardList,
		way = way,
		luckyItem = pb.luckyItem,
	})
end

--- 处理召唤
function ModelHalidom:DisposeHalidomDrawReq(drawType)
	if self:IsDrawReqProtect() then return end

	local hasFree = false
	local drawNum = 1
	local drawPayItem = self:GetHalidomExpend()
	if drawType == ModelHalidom.TYPE_DRAW_MORE then
		drawNum = self:GetHalidomMoreNum()
		drawPayItem = self:GetHalidomMoreExpend()
	else
		hasFree = self:CheckRPHasFreeNum()
	end
	if not hasFree then
		local isEnough = gModelGeneral:CheckItemEnough(drawPayItem.itemId,drawPayItem.itemNum,true)
		if not isEnough then return end
	end

	self:OnHalidomDrawReq(drawType)
end

function ModelHalidom:SetDrawReqProtect(isProtect)
	if isProtect then
		self._drawTime = 0
	else
		self._drawTime = Time.time
	end
end

function ModelHalidom:IsDrawReqProtect()
	if not self._drawTime then return false end
	local timePast = Time.time - self._drawTime
	if timePast > 1 then return false end
	return true
end


---@param oldHalidom StructHalidomObjInfo
