function ModelHalidom:GetHalidomUpStarAttrList(oldHalidom,newHalidom)
	if not oldHalidom or not newHalidom then return {} end
	local oldHalidomAttrs = self:GetHalidomStarAttrListByRefId(oldHalidom.starRefId)
	local newHalidomAttrs = self:GetHalidomStarAttrListByRefId(newHalidom.starRefId)
	return LUtil.GetContrastCommonAttrList(oldHalidomAttrs,newHalidomAttrs)
end


function ModelHalidom:DisposeItemCode(code,refId)
	if not code or not refId then return end

	local halidomRefId = gModelItem:GetItem2HalidomRefId(refId)
	if not halidomRefId then return end

	local compoundNum = gModelItem:GetItem2HalidomCompoundNum(refId)
	if not compoundNum or compoundNum < 1 then return end

	local itemRef = gModelItem:GetRefByRefId(refId)
	if not itemRef then return end

	local hasJump = not string.isempty(itemRef.jump)
	local hasNum = gModelItem:GetNumByRefId(refId)
	local isEnough = hasNum >= compoundNum

	local success = false

	if code == ModelItem.BTNCODE_HALIDOM_PRE then
--[[		local halidomObj = self:GetHalidomObjByRefId(halidomRefId)
		if gModelHalidom:CheckIsHalidomObjAct(halidomRefId) and halidomObj then
			self:OpenOptHalidomTips({
				halidomObj = halidomObj,
				refId = halidomRefId
			})
		else
			self:OpenFullMaxHalidomTips({refId = halidomRefId})
		end]]
		self:CommonOpenTips(halidomRefId)
	elseif code == ModelItem.BTNCODE_HALIDOM_PRENOTOPT then
		self:OpenNotOptFullMaxHalidomTips({refId = halidomRefId})
	elseif code == ModelItem.BTNCODE_HALIDOM_USE then
		if isEnough then
			--- 2024/5/28： 不直接操作，打开弹窗
			--gModelHalidom:OnHalidomStarUpReq(halidomRefId)

--[[			self:OpenFullMaxHalidomTips({
				refId = halidomRefId,
			})]]
			self:CommonOpenTips(halidomRefId)

			success = true
		else
			if hasJump then
				gModelGeneral:OpenGetWayWnd({ itemId = refId })
			else
				GF.ShowMessage(string.replace(ccClientText(41545),gModelItem:GetNameByRefId(refId)))
			end
		end
	elseif code == ModelItem.BTNCODE_HALIDOM_COMPOUND then
		if isEnough then
			--- 2024/5/28： 不直接操作，打开弹窗
			--gModelHalidom:OnHalidomStarUpReq(halidomRefId)
--[[			if gModelHalidom:CheckIsHalidomObjAct(halidomRefId) then
				self:OpenOptHalidomTips({
					halidomObj = self:GetHalidomObjByRefId(halidomRefId),
					refId = halidomRefId
				})
			else
				self:OpenFullMaxHalidomTips({
					refId = halidomRefId,
				})
			end]]

			self:CommonOpenTips(halidomRefId)
			success = true
		else
			if hasJump then
				gModelGeneral:OpenGetWayWnd({ itemId = refId })
			else
				GF.ShowMessage(string.replace(ccClientText(41545),gModelItem:GetNameByRefId(refId)))
			end
		end
	end
	return success
end

function ModelHalidom:CommonOpenTips(halidomRefId)
	local halidomObj = self:GetHalidomObjByRefId(halidomRefId)
	if gModelHalidom:CheckIsHalidomObjAct(halidomRefId) and halidomObj then
		self:OpenOptHalidomTips({
			halidomObj = halidomObj,
			refId = halidomRefId
		})
	else
		self:OpenFullMaxHalidomTips({refId = halidomRefId})
	end
end


