	for attrRefId,attrTypeData in pairs(curAttrMap) do
		local nextAttrTypeData = nextAttrMap[attrRefId]
		for attrType,attrNum in pairs(attrTypeData) do
			local nextAttrNum = nextAttrTypeData and nextAttrTypeData[attrType]
			local hasNextNum = nextAttrNum and nextAttrNum > 0
			table.insert(list,{
				attrRefId = attrRefId,
				attrType = attrType,
				attrNum = attrNum,
				nextAttrNum = hasNextNum and nextAttrNum - attrNum or -1,
			})
		end
	end
	return list
end


function ModelHalidom:GetShowStarImg(star,refId)
	local maxStarLv = false
	if refId then
		maxStarLv = self:CheckHalidomIsMaxStarLv(refId,star)
		if maxStarLv then
			--- 按照需求写死，满级则显示一颗星星,
			return {
				maxStarLv = true,
				starImg = "hero_icon_star5",
				showNum = 1,
			}
		end
	end
	local img, temp, index = LUtil.GetHeroStarImg(star)
	return {
		maxStarLv = maxStarLv,
		starImg = img,
		showNum = temp,
	}
end


