---- 所有的属性显示
function ModelHalidom:OpenAttrOverViewByMySelf()
	local recordAttrList = {}
	--- 反馈单   需要加上 圣物
	local objMap = self:GetHalidomObjMap()
	for k,v in pairs(objMap) do
		self:_GetHalidomObjAttrListByObj(v,recordAttrList)
	end
	local collectMap = self:GetHalidomCollectMap()
	for k,v in pairs(collectMap) do
		self:_GetHalidomCollectObjAttrListByObj(v,recordAttrList)
	end
	self:OpenAttrOVerDispose(recordAttrList)
end

---- 根据 collectType 类型 显示属性
function ModelHalidom:OpenAttrOverViewMySelfByRefId(collectType)
	local recordAttrList = {}
	local objMap = self:GetHalidomObjMap()
	for k,v in pairs(objMap) do
		if self:GetHalidomTypeByRefId(v.refId) == collectType then
			self:_GetHalidomObjAttrListByObj(v,recordAttrList)
		end
	end
	local collectMap = self:GetHalidomCollectMap()
	---@type StructHalidomCollectObjInfo
	local collectObj = collectMap[collectType]
	if collectObj then
		self:_GetHalidomCollectObjAttrListByObj(collectObj,recordAttrList)
	end
	self:OpenAttrOVerDispose(recordAttrList,self:GetHalidomTypeNameByRefId(collectType))
end

--- 获取 圣物Obj 的属性列表
---@param halidomObj StructHalidomObjInfo
function ModelHalidom:_GetHalidomObjAttrListByObj(halidomObj,recordAttrList)
	if not halidomObj then return end
	local halidomStarRefId = halidomObj.starRefId
	local attrList = self:GetHalidomStarAttrListByRefId(halidomStarRefId)
	if attrList and #attrList > 0 then
		for idx,val in ipairs(attrList) do
			table.insert(recordAttrList,val)
		end
	end
	local topNum = self:GetHalidomStarTopNumByRefId(halidomObj.starRefId)
	if topNum < 1 then
		--- 2024/6/13： 没有任务进度的话，是直接加上去
		local addAttrList = self:GetHalidomStarAddAttrListByRefId(halidomStarRefId)
		if addAttrList and #addAttrList > 0 then
			for idx,val in ipairs(addAttrList) do
				table.insert(recordAttrList,{
					attrRefId = val.attrRefId,
					attrType = val.attrType,
					attrNum = val.attrNum,
				})
			end
		end
	else
		if halidomObj.taskFinishCnt < 1 then return end

		--- 完成对应任务次数
		local taskFinishCnt = halidomObj.taskFinishCnt
		local addAttrList = self:GetHalidomStarAddAttrListByRefId(halidomStarRefId)
		if addAttrList and #addAttrList > 0 then
			for idx,val in ipairs(addAttrList) do
				table.insert(recordAttrList,{
					attrRefId = val.attrRefId,
					attrType = val.attrType,
					attrNum = val.attrNum * taskFinishCnt,
				})
			end
		end
	end
end

--- 获取 圣物收藏Obj 的属性列表
---@param halidomCollectObj StructHalidomCollectObjInfo
function ModelHalidom:_GetHalidomCollectObjAttrListByObj(halidomCollectObj,recordAttrList)
	local attrList = self:GetHalidomCollectAttrByRefId(halidomCollectObj.refId)
	if attrList and #attrList > 0 then
		for idx,val in ipairs(attrList) do
			table.insert(recordAttrList,val)
		end
	end
end

function ModelHalidom:OpenAttrOVerDispose(recordAttrList,title)
	local attrKeyMap = LUtil.GetCommonAttrKeyList(recordAttrList)
	local list = {}
	for attrRefId,attrTypeData in pairs(attrKeyMap) do
		for attrType,attrNum in pairs(attrTypeData) do
			table.insert(list,{
				attrRefId = attrRefId,
				attrType = attrType,
				attrNum = attrNum,
			})
		end
	end
	table.sort(list,function(a, b)
		local sortA,sortB = gModelHero:GetCommonAttrSortFunc(a,b)
		return  sortA < sortB
	end)
	self:OpenAttrOverView({
		attrList = list,
		titleTxt = title,
	})
end

function ModelHalidom:OpenAttrOverView(param)
	GF.OpenWnd("UISdAttrOverView",param)
end




