	local value = status and 1 or 0
	LPlayerPrefs.SetHalidomDrawJumpAni(value)
end

function ModelHalidom:EnterHalidomCall()
	self._isEnterHalidomCall = true
end
---------------------------- 红点 start

--- 是否有免费次数
function ModelHalidom:CheckRPHasFreeNum()
	local freeDrawCnt = self:GetHalidomFreeDrawCnt()
	return freeDrawCnt > 0
end


--- 存在可进行1次多抽的道具
function ModelHalidom:CheckRPHasMoreDraw()
	--- 2024/6/3：已经进入召唤后，本次登陆不再提示
	if self._isEnterHalidomCall then return false end

	local halidomMoreExpend = self:GetHalidomMoreExpend()
	if not halidomMoreExpend then return false end
	local hasNum = gModelItem:GetNumByRefId(halidomMoreExpend.itemId)
	return hasNum >= halidomMoreExpend.itemNum
end


--- 激活红点
function ModelHalidom:CheckRPHasAct()
	if not self._initHalidomRefMap then return false end

	local objMap = self:GetHalidomObjMap()
	for k,v in pairs(self._initHalidomRefMap) do
		if not objMap[k] and self:CheckRPHasActByRefId(k) then return true end
	end
	return false
end

function ModelHalidom:CheckRPActHalidomIsLimit(refId)
	local type = self:GetHalidomTypeByRefId(refId)
	local condition = self:GetHalidomTypeConditionByRefId(type)
	if condition and condition > 0 then
		return condition > self:GetHalidomJackpotLv()
	end
	return false
end

--- 激活红点
function ModelHalidom:CheckRPHasActByRefId(refId)
	--- 2024/09/03：只要有道具，都可以激活
--[[	if self:CheckRPActHalidomIsLimit(refId) then
		--- 激活限制
		return false
	end]]
	local numItem = self:GetSplitHalidomNumItemByRefId(refId)
	if numItem and gModelGeneral:CheckItemEnough(numItem.itemId,numItem.itemNum) then
		return true
	end
	return false
end

--- 升星红点
function ModelHalidom:CheckRPHasUpStar()
	local objMap = self:GetHalidomObjMap()
	if not objMap then return false end

	---@param v StructHalidomObjInfo
	for k,v in pairs(objMap) do
		if self:CheckRPHasUpStarByHalidomObj(v) then
			return true
		end
		if self:CheckRPHalidomHasExp(v) then
			return true
		end
	end
	return false
end

--- 是否有足够的道具升星
---@param obj StructHalidomObjInfo
function ModelHalidom:CheckRPHasUpStarByHalidomObj(obj)
	if not obj then return false end
	if self:CheckHalidomObjIsMaxStarLv(obj.refId) then return false end
	local nextNum = self:GetSplitHalidomStarNextNumByRefId(obj.starRefId)
	if nextNum and gModelGeneral:CheckItemEnough(nextNum.itemId,nextNum.itemNum) then
		return true
	end
	return false
end

--- 是否有提供收藏经验
---@param obj StructHalidomObjInfo
function ModelHalidom:CheckRPHalidomHasExp(obj)
	if not obj then return end
	return obj:CheckHasAddExp()
end

--- 积分奖励可领取
function ModelHalidom:CheckRPIntegralCall()
	local jackpotLv = self:GetHalidomJackpotLv()
	local datas = self:GetHalidomLuckyRewardsByJackpotLv(jackpotLv) or {}
	if #datas < 1 then return false end

	local progressRewardId = self:GetHalidomProgressRewardId()
	local curItemNum = self:GetCurJackpotItemNum()
	for i,v in ipairs(datas) do
		if curItemNum >= v.grad and progressRewardId < v.refId then
			return true
		end
	end
	return false
end

--- 全部红点
function ModelHalidom:CheckRPAllShow()
	if self:CheckRPHasFreeNum() then return true end
	if self:CheckRPHasMoreDraw() then return true end
	if self:CheckRPHasAct() then return true end
	if self:CheckRPHasUpStar() then return true end
	return false
end

--- 图鉴红点
function ModelHalidom:CheckRPHasBook()
	if self:CheckRPHasAct() then return true end
	if self:CheckRPHasUpStar() then return true end
	return false
end


